import sys

def main():
    n = int(sys.stdin.readline())
    p = [0] * n
    used = set()

    for i in range(n):
        a = [1] * n
        a[i] = 2
        print('? ' + ' '.join(map(str, a)))
        sys.stdout.flush()
        k = int(sys.stdin.readline())
        if k == 0:
            p[i] = 1
        else:
            p[i] = 2
        used.add(p[i])

    for i in range(n):
        if p[i] == 0:
            for j in range(1, n+1):
                if j not in used:
                    p[i] = j
                    used.add(j)
                    break

    print('! ' + ' '.join(map(str, p)))
    sys.stdout.flush()

if __name__ == "__main__":
    main()

